    // skipSplash=1鬯ｩ謳ｾ・ｽ・ｵ郢晢ｽｻ繝ｻ・ｺ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｮ鬯ｮ・ｯ隲幢ｽｶ繝ｻ・ｽ繝ｻ・｣驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｴ鬯ｮ・ｯ繝ｻ・ｷ郢晢ｽｻ繝ｻ・ｷ鬮ｯ蜈ｷ・ｽ・ｹ郢晢ｽｻ繝ｻ・ｻ鬩幢ｽ｢隴趣ｽ｢繝ｻ・ｽ繝ｻ・ｻ鬯ｩ蟷｢・ｽ・｢郢晢ｽｻ繝ｻ・ｧ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｹ鬯ｩ蟷｢・ｽ・｢髫ｴ諠ｹ・ｸ讖ｸ・ｽ・ｹ繝ｻ・ｲ郢晢ｽｻ闕ｳ・ｻ繝ｻ・ｸ繝ｻ・ｷ郢晢ｽｻ繝ｻ・ｹ髫ｴ謫ｾ・ｽ・ｴ驛｢譎｢・ｽ・ｻ鬩搾ｽｵ繝ｻ・ｺ髯ｷ・･隰ｫ・ｾ繝ｻ・ｽ繝ｻ・ｹ髫ｴ雜｣・ｽ・｢郢晢ｽｻ繝ｻ・ｽ郢晢ｽｻ繝ｻ・･鬯ｩ蟷｢・ｽ・｢郢晢ｽｻ繝ｻ・ｧ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・｢鬯ｩ蟷｢・ｽ・｢髫ｴ荵励・繝ｻ・ｽ繝ｻ・ｹ髫ｴ竏ｵ・ｻ繝ｻ・ｱ・ｪ郢晢ｽｻ繝ｻ・ｹ髫ｴ雜｣・ｽ・｢郢晢ｽｻ繝ｻ・ｽ郢晢ｽｻ繝ｻ・ｼ鬯ｩ蟷｢・ｽ・｢郢晢ｽｻ繝ｻ・ｧ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｷ鬯ｩ蟷｢・ｽ・｢髫ｴ雜｣・ｽ・｢郢晢ｽｻ繝ｻ・ｽ郢晢ｽｻ繝ｻ・ｧ鬯ｩ蟷｢・ｽ・｢髫ｴ雜｣・ｽ・｢郢晢ｽｻ繝ｻ・ｽ郢晢ｽｻ繝ｻ・ｳ鬯ｩ蟷｢・ｽ・｢郢晢ｽｻ繝ｻ・ｧ鬮ｯ蜿･・ｹ・｢繝ｻ・ｽ繝ｻ・ｵ鬩搾ｽｵ繝ｻ・ｺ髯晢ｽｶ繝ｻ・ｷ郢晢ｽｻ繝ｻ・ｹ郢晢ｽｻ繝ｻ・ｧ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｭ鬯ｩ蟷｢・ｽ・｢髫ｴ謫ｾ・ｽ・ｴ驛｢譎｢・ｽ・ｻ鬩幢ｽ｢隴趣ｽ｢繝ｻ・ｽ繝ｻ・ｻ
    const shouldSkipSplash = new URLSearchParams(window.location.search).get('skipSplash') === '1';

    if (shouldSkipSplash) {
      // 鬯ｩ蟷｢・ｽ・｢郢晢ｽｻ繝ｻ・ｧ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｹ鬯ｩ蟷｢・ｽ・｢髫ｴ諠ｹ・ｸ讖ｸ・ｽ・ｹ繝ｻ・ｲ郢晢ｽｻ闕ｳ・ｻ繝ｻ・ｸ繝ｻ・ｷ郢晢ｽｻ繝ｻ・ｹ髫ｴ謫ｾ・ｽ・ｴ驛｢譎｢・ｽ・ｻ鬩搾ｽｵ繝ｻ・ｺ髯ｷ・･隰ｫ・ｾ繝ｻ・ｽ繝ｻ・ｹ髫ｴ雜｣・ｽ・｢郢晢ｽｻ繝ｻ・ｽ郢晢ｽｻ繝ｻ・･鬯ｩ蟷｢・ｽ・｢郢晢ｽｻ繝ｻ・ｧ鬮ｯ蜿･・ｹ・｢繝ｻ・ｽ繝ｻ・ｵ鬩搾ｽｵ繝ｻ・ｺ髯晢ｽｶ繝ｻ・ｷ郢晢ｽｻ繝ｻ・ｹ郢晢ｽｻ繝ｻ・ｧ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｭ鬯ｩ蟷｢・ｽ・｢髫ｴ謫ｾ・ｽ・ｴ驛｢譎｢・ｽ・ｻ鬩幢ｽ｢隴趣ｽ｢繝ｻ・ｽ繝ｻ・ｻ鬯ｩ謳ｾ・ｽ・ｵ郢晢ｽｻ繝ｻ・ｺ鬮ｯ・ｷ繝ｻ・ｷ郢晢ｽｻ繝ｻ・ｶ驛｢譎｢・ｽ・ｻ鬩阪・謌溯ｬ千､ｼ・ｹ譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｴ鬯ｮ・ｯ繝ｻ・ｷ郢晢ｽｻ繝ｻ・ｷ鬮ｯ蜈ｷ・ｽ・ｹ郢晢ｽｻ繝ｻ・ｻ鬩幢ｽ｢隴趣ｽ｢繝ｻ・ｽ繝ｻ・ｻ鬯ｮ・ｯ繝ｻ・ｷ髯槭ｅ繝ｻ繝ｻ・ｽ繝ｻ・ｽ郢晢ｽｻ繝ｻ・ｳ鬯ｮ・ｯ雋・ｽｯ繝ｻ・ｶ繝ｻ・｣郢晢ｽｻ繝ｻ・ｽ郢晢ｽｻ繝ｻ・ｧ鬯ｩ謳ｾ・ｽ・ｵ郢晢ｽｻ繝ｻ・ｺ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｫ鬯ｩ蟷｢・ｽ・｢髫ｴ雜｣・ｽ・｢郢晢ｽｻ繝ｻ・ｽ郢晢ｽｻ繝ｻ・｡鬯ｩ蟷｢・ｽ・｢郢晢ｽｻ繝ｻ・ｧ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・､鬯ｩ蟷｢・ｽ・｢髫ｴ雜｣・ｽ・｢郢晢ｽｻ繝ｻ・ｽ郢晢ｽｻ繝ｻ・ｳ鬯ｯ・ｮ繝ｻ・ｯ郢晢ｽｻ繝ｻ・ｦ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｨ鬯ｯ・ｩ驕ｨ繧托ｽｽ・ｼ陞滂ｽｲ繝ｻ・ｽ繝ｻ・ｽ郢晢ｽｻ繝ｻ・ｺ
      if (mainContent) mainContent.classList.add('visible');
      document.body.style.overflowY = 'auto';
      if (stickyCta) stickyCta.style.display = 'block';
      initScrollObserver();
    }

    if (!shouldSkipSplash && splashElement) {
      const engine = Engine.create();
      engine.world.gravity.y = 1.5;
      const world = engine.world;

      let width = window.innerWidth;
      let height = window.innerHeight;

      const render = Render.create({
        element: splashElement,
        engine: engine,
        options: { width, height, background: 'transparent', wireframes: false }
      });

      const wallOptions = { isStatic: true, render: { visible: false } };
      const floor = Bodies.rectangle(width / 2, height + 50, width + 200, 100, wallOptions);
      const leftWall = Bodies.rectangle(-60, height / 2, 120, height + 200, wallOptions);
      const rightWall = Bodies.rectangle(width + 60, height / 2, 120, height + 200, wallOptions);
      Composite.add(world, [floor, leftWall, rightWall]);

      function preloadImages(urls) {
        const tasks = urls.map(url => new Promise(resolve => {
          const img = new Image();
          img.onload = () => resolve({ url, ok: true });
          img.onerror = () => resolve({ url, ok: false });
          img.src = url;
        }));
        return Promise.all(tasks);
      }

      let AVAILABLE_ICON_URLS = [];
      let count = 0;
      let dropTimer = null;

      function startDropping() {
        dropTimer = setInterval(() => {
          if (count >= TOTAL_ICONS) { clearInterval(dropTimer); return; }

          const xPos = Math.random() * (width - 120) + 60;
          const hasSprite = AVAILABLE_ICON_URLS.length > 0;
          const texture = hasSprite ? AVAILABLE_ICON_URLS[Math.floor(Math.random() * AVAILABLE_ICON_URLS.length)] : null;

          const opts = { restitution: 0.55, friction: 0.08, frictionAir: 0.03, render: {} };

          if (hasSprite) {
            opts.render.sprite = { texture, xScale: ICON_SIZE / 512, yScale: ICON_SIZE / 512 };
          } else {
            const fallbackColors = ['#8FD7FF', '#F7A7C6', '#FFA24A', '#9C7BFF'];
            opts.render.fillStyle = fallbackColors[Math.floor(Math.random() * fallbackColors.length)];
            opts.render.strokeStyle = 'rgba(255,255,255,0.35)';
            opts.render.lineWidth = 2;
          }

          const icon = Bodies.circle(xPos, -60, ICON_SIZE / 2, opts);
          Composite.add(world, icon);
          count++;
        }, SPAWN_RATE);
      }

      Render.run(render);
      const runner = Runner.create();
      Runner.run(runner, engine);

      preloadImages(ICON_URLS).then(results => {
        AVAILABLE_ICON_URLS = results.filter(r => r.ok).map(r => r.url);
        startDropping();
      });

      splashElement?.addEventListener('click', () => {
        if (dropTimer) clearInterval(dropTimer);

        const bodies = Composite.allBodies(world);
        bodies.forEach(body => {
          if (!body.isStatic) {
            const force = 0.5 * body.mass;
            Body.applyForce(body, body.position, {
              x: (Math.random() - 0.5) * force,
              y: (Math.random() - 1.5) * force
            });
          }
        });

        setTimeout(() => {
          splashElement.classList.add('hidden');
          mainContent.classList.add('visible');
          document.body.style.overflowY = 'auto';
          initScrollObserver();
          if (stickyCta) stickyCta.style.display = 'block';

          setTimeout(() => {
            Render.stop(render);
            Runner.stop(runner);
            engine.enabled = false;
            splashElement.remove();
          }, 1200);
        }, 500);
      });
    } // end if(!shouldSkipSplash)

    window.addEventListener('resize', () => {
      if (!shouldSkipSplash && typeof render !== 'undefined') {
        width = window.innerWidth;
        height = window.innerHeight;

        render.canvas.width = width;
        render.canvas.height = height;
        render.options.width = width;
        render.options.height = height;

        Body.setPosition(floor, { x: width / 2, y: height + 50 });
        Body.setPosition(leftWall, { x: -60, y: height / 2 });
        Body.setPosition(rightWall, { x: width + 60, y: height / 2 });
      }

      const imagePopup = document.getElementById('imagePopup');
      if (imagePopup && imagePopup.classList.contains('is-open')) {
        updateImageGallery();
      }
    }, { passive: true });

    /* ===== Retro Camera Demo (Overlay) ===== */
    window.openViewfinder = null;

    (() => {
      const overlay = document.getElementById('vfOverlay');
      const closeBtn = document.getElementById('vfClose');
      const backdrop = document.getElementById('vfBackdrop');

      const viewfinder = document.getElementById('rcViewfinder');
      const container = document.getElementById('rcPhotoContainer');
      const snapBtn = document.getElementById('rcSnap');

      if (!overlay || !closeBtn || !backdrop || !viewfinder || !container || !snapBtn) return;

      let prevBodyOverflow = '';
      let prevBodyOverflowY = '';
      let prevHtmlOverflow = '';

      const SEED = [
        "img/mobby/mobby_pink.jpg",
        "img/mobby/mobby_purple.jpg",
        "img/mobby/mobby_blue.jpg",
        "img/mobby/mobby_orange.jpg",
        "img/mobby/mobby_pink2.jpg",
        "img/mobby/mobby_yellow.jpg",
        "img/mobby/mobby_purple2.jpg",
        "img/mobby/mobby_blue2.jpg"
      ];
      let photos = SEED.map((url, i) => ({ id: i + 1, url }));

      let dustMade = false;

      function renderPhotos() {
        const existing = Array.from(container.children);
        const photosToShow = photos.slice(0, 5);

        photosToShow.forEach((photo, index) => {
          let el = document.getElementById(`rc-p-${photo.id}`);

          if (!el) {
            el = document.createElement('div');
            el.id = `rc-p-${photo.id}`;
            el.className = 'rc-polaroid rc-age-0';
            el.style.opacity = '0';

            const img = document.createElement('img');
            img.src = photo.url;
            img.alt = `photo ${index + 1}`;
            img.draggable = false;

            el.appendChild(img);
            container.appendChild(el);

            setTimeout(() => { el.style.opacity = '1'; }, 50);
          }

          el.classList.remove('rc-age-0', 'rc-age-1', 'rc-age-2', 'rc-age-3', 'rc-age-4');
          el.classList.add(`rc-age-${index}`);
        });

        const currentIds = photosToShow.map(p => `rc-p-${p.id}`);
        existing.forEach(el => {
          if (!currentIds.includes(el.id)) {
            el.style.opacity = '0';
            el.style.transform = 'scale(0.5)';
            setTimeout(() => el.remove(), 800);
          }
        });
      }

      function addFlashEffect() {
        const flash = document.createElement('div');
        flash.style.position = 'absolute';
        flash.style.inset = '0';
        flash.style.background =
          'radial-gradient(circle at center, #fff 0%, rgba(255,255,255,0.8) 30%, rgba(255,255,255,0) 65%)';
        flash.style.opacity = '0.92';
        flash.style.zIndex = '200';
        flash.style.pointerEvents = 'none';
        flash.style.transition = 'opacity 0.25s ease-out';

        viewfinder.appendChild(flash);

        requestAnimationFrame(() => {
          requestAnimationFrame(() => { flash.style.opacity = '0'; });
        });

        setTimeout(() => flash.remove(), 350);
      }

      function createDust() {
        if (dustMade) return;
        dustMade = true;
        for (let i = 0; i < 40; i++) {
          const d = document.createElement('div');
          d.className = 'rc-dust';
          d.style.left = `${Math.random() * 100}%`;
          d.style.top = `${Math.random() * 100}%`;
          const size = Math.random() * 2;
          d.style.width = `${size}px`;
          d.style.height = `${size}px`;
          d.style.opacity = String(Math.random() * 0.5);
          viewfinder.appendChild(d);
        }
      }

      const DEMO_POOL = [
        "img/shutter/1.jpg",
        "img/shutter/2.jpg",
        "img/shutter/3.jpg",
        "img/shutter/4.jpg",
        "img/shutter/5.jpg",
        "img/shutter/6.jpg",
        "img/shutter/7.jpg",
        "img/shutter/8.jpg",
        "img/shutter/9.jpg",
        "img/shutter/10.jpg",
      ];
      let demoCursor = 0;

      function takePhoto() {
        const newId = Date.now();
        const baseUrl = DEMO_POOL[demoCursor % DEMO_POOL.length];
        demoCursor++;
        const url = `${baseUrl}?cb=${newId}`;

        photos.unshift({ id: newId, url });
        if (photos.length > 5) photos.pop();

        renderPhotos();
        addFlashEffect();
      }

      function open() {
        overlay.classList.add('is-open');
        overlay.setAttribute('aria-hidden', 'false');

        prevBodyOverflow = document.body.style.overflow;
        prevBodyOverflowY = document.body.style.overflowY;
        prevHtmlOverflow = document.documentElement.style.overflow;

        document.body.style.overflow = 'hidden';
        document.body.style.overflowY = 'hidden';
        document.documentElement.style.overflow = 'hidden';

        createDust();
        renderPhotos();
      }

      function close() {
        overlay.classList.remove('is-open');
        overlay.setAttribute('aria-hidden', 'true');

        document.body.style.overflow = prevBodyOverflow;
        document.body.style.overflowY = prevBodyOverflowY;
        document.documentElement.style.overflow = prevHtmlOverflow;
      }

      window.openViewfinder = function (shutterElement = null) {
        const shutter = shutterElement || eyeShutter;
        if (shutter) {
          shutter.classList.remove('play');
          void shutter.offsetWidth;
          shutter.classList.add('play');
        }
        setTimeout(() => { open(); }, 180);
      };

      snapBtn.addEventListener('click', takePhoto);
      closeBtn.addEventListener('click', close);
      backdrop.addEventListener('click', close);
      window.addEventListener('keydown', (e) => {
        if (!overlay.classList.contains('is-open')) return;
        if (e.key === 'Escape') close();
      });
    })();

    layoutRing();

    /* ===== 鬯ｩ蟷｢・ｽ・｢髫ｴ蠑ｱ繝ｻ繝ｻ・ｺ繝ｻ・｢鬩幢ｽ｢隴趣ｽ｢繝ｻ・ｽ繝ｻ・｣鬯ｩ蟷｢・ｽ・｢髫ｴ諠ｹ・ｸ讖ｸ・ｽ・ｹ繝ｻ・ｲ鬩搾ｽｵ繝ｻ・ｺ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｹ髫ｴ謫ｾ・ｽ・ｴ驛｢譎｢・ｽ・ｻ鬩幢ｽ｢隴趣ｽ｢繝ｻ・ｽ繝ｻ・ｻ鬯ｮ・ｯ陷茨ｽｷ繝ｻ・ｽ繝ｻ・ｻ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｶ鬯ｮ・ｯ雋・ｽｷ隴ｯ竏壹・繝ｻ・ｽ郢晢ｽｻ繝ｻ・｡ ===== */
    let typingInterval = null;

    function startTypingAnimation(element) {
      if (!element) return;
      const fullText = element.getAttribute('data-text') || element.textContent.trim();
      if (!fullText) return;

      if (typingInterval) {
        clearInterval(typingInterval);
        typingInterval = null;
      }

      element.textContent = '';
      element.classList.remove('typing-complete');

      let currentIndex = 0;
      const typingSpeed = 50;

      typingInterval = setInterval(() => {
        if (currentIndex < fullText.length) {
          element.textContent = fullText.substring(0, currentIndex + 1);
          currentIndex++;
        } else {
          clearInterval(typingInterval);
          typingInterval = null;
          element.classList.add('typing-complete');
        }
      }, typingSpeed);
    }

    function openPopup(popupId) {
      const popup = document.getElementById(popupId);
      if (!popup) return;
      popup.classList.add('is-open');
      popup.setAttribute('aria-hidden', 'false');
      document.body.style.overflow = 'hidden';

      if (popupId === 'messagePopup') {
        const creatorText = popup.querySelector('.creator-text');
        if (creatorText) {
          setTimeout(() => { startTypingAnimation(creatorText); }, 300);
        }
      }

      if (popupId === 'videoPopup') {
        const video = popup.querySelector('#mobbyVideo');
        if (video) {
          setTimeout(() => {
            video.currentTime = 0;
            video.play().catch(() => { });
          }, 300);
        }
      }

      if (popupId === 'encyclopediaPopup') {
        setTimeout(() => { initEncyclopedia(); }, 100);
      }
    }

    function closePopup(popupId) {
      const popup = document.getElementById(popupId);
      if (!popup) return;

      if (typingInterval) {
        clearInterval(typingInterval);
        typingInterval = null;
      }

      popup.classList.remove('is-open');
      popup.setAttribute('aria-hidden', 'true');
      document.body.style.overflow = '';

      if (popupId === 'messagePopup') {
        const creatorText = popup.querySelector('.creator-text');
        if (creatorText) {
          creatorText.textContent = '';
          creatorText.classList.remove('typing-complete');
        }
      }

      if (popupId === 'videoPopup') {
        const video = popup.querySelector('#mobbyVideo');
        if (video) {
          video.pause();
          video.currentTime = 0;
        }
      }
    }

    /* ===== Encyclopedia (鬯ｮ・ｯ隲帑ｺ･諠ｧ郢晢ｽｻ繝ｻ・ｽ郢晢ｽｻ繝ｻ・ｳ鬯ｯ・ｯ繝ｻ・ｮ髣比ｼ夲ｽｽ・｣驛｢譎｢・ｽ・ｻ ===== */
