    let encyclopediaActiveTab = "all";

    function initEncyclopedia() {
      const tabsEl = document.getElementById('encyclopediaTabs');
      const gridEl = document.getElementById('encyclopediaGrid');
      if (!tabsEl || !gridEl) return;

      // Render tabs
      tabsEl.innerHTML = ENCYCLOPEDIA_CATEGORIES.map(c => {
        const isActive = c.key === encyclopediaActiveTab;
        return `<button data-cat="${c.key}" style="
          padding:8px 16px;border-radius:20px;font-size:13px;font-weight:700;cursor:pointer;border:2px solid ${c.color};
          background:${isActive ? c.color : 'transparent'};color:${isActive ? '#fff' : c.color};
          transition:all 0.2s ease;
        ">${c.label}</button>`;
      }).join('');

      // Tab click
      tabsEl.querySelectorAll('button').forEach(btn => {
        btn.addEventListener('click', () => {
          encyclopediaActiveTab = btn.dataset.cat;
          initEncyclopedia();
        });
      });

      // Render grid
      const items = encyclopediaActiveTab === 'all'
        ? ENCYCLOPEDIA_DATA
        : ENCYCLOPEDIA_DATA.filter(d => d.cat === encyclopediaActiveTab);
      const catInfo = encyclopediaActiveTab === 'all'
        ? { key: 'all', label: '郢晢ｽｻ雋企屮・ｽ・ｨ鬯・､ｧ・ｸ繝ｻ鬯ｮ・｣陋ｹ繝ｻ・ｽ・ｽ繝ｻ・ｳ郢晢ｽｻ邵ｺ・､・つ鬯ｯ・ｮ繝ｻ・ｫ髯具ｽｹ郢晢ｽｻ繝ｻ・ｽ繝ｻ・ｽ郢晢ｽｻ繝ｻ・ｧ', color: '#6b7280' }
        : ENCYCLOPEDIA_CATEGORIES.find(c => c.key === encyclopediaActiveTab);


      // Toggle compact class for all-tab mobile view
      if (encyclopediaActiveTab === 'all') {
        gridEl.classList.add('ency-compact');
      } else {
        gridEl.classList.remove('ency-compact');
      }

      if (encyclopediaActiveTab === 'all') {
        // Group by category with section headers
        const catOrder = ['school_m', 'school_f', 'mama', 'night', 'stan', 'love'];
        let html = '';
        let globalIdx = 0;
        catOrder.forEach(catKey => {
          const catItems = ENCYCLOPEDIA_DATA.filter(d => d.cat === catKey);
          const ci = ENCYCLOPEDIA_CATEGORIES.find(c => c.key === catKey);
          if (!ci || catItems.length === 0) return;
          catItems.forEach((item, i) => {
            html += `
            <div class="ency-card" data-idx="${globalIdx}" style="
              background:#fff;border-radius:14px;overflow:hidden;cursor:pointer;
              box-shadow:0 2px 12px rgba(0,0,0,0.08);border:1px solid rgba(0,0,0,0.06);
              transition:transform 0.2s ease,box-shadow 0.2s ease;
              animation:fadeIn 0.3s ease ${(globalIdx) * 0.02}s both;
            ">
              <div style="aspect-ratio:1/1;overflow:hidden;background:#f5f0eb;border-radius:inherit;">
                <img src="${item.img}" alt="${item.name}" loading="lazy" style="width:100%;height:100%;object-fit:cover;" onerror="this.style.display='none'">
              </div>
            </div>`;
            globalIdx++;
          });
        });
        gridEl.innerHTML = html;
      } else {
        gridEl.innerHTML = items.map((item, i) => `
        <div class="ency-card" data-idx="${i}" style="
          background:#fff;border-radius:14px;overflow:hidden;cursor:pointer;
          box-shadow:0 2px 12px rgba(0,0,0,0.08);border:1px solid rgba(0,0,0,0.06);
          transition:transform 0.2s ease,box-shadow 0.2s ease;
          animation:fadeIn 0.3s ease ${i * 0.03}s both;
        ">
          <div style="aspect-ratio:1/1;overflow:hidden;background:#f5f0eb;">
            <img src="${item.img}" alt="${item.name}" loading="lazy" style="width:100%;height:100%;object-fit:cover;" onerror="this.style.display='none'">
          </div>
          <div style="padding:8px 10px 10px;">
            <div style="font-size:11px;font-weight:700;color:#4a3728;line-height:1.3;min-height:28px;display:flex;align-items:center;">${item.name}</div>
          </div>
        </div>
      `).join('');
      }


      // Card hover
      gridEl.querySelectorAll('.ency-card').forEach(card => {
        card.addEventListener('mouseenter', () => { card.style.transform = 'translateY(-3px)'; card.style.boxShadow = '0 6px 20px rgba(0,0,0,0.12)'; });
        card.addEventListener('mouseleave', () => { card.style.transform = ''; card.style.boxShadow = ''; });
        card.addEventListener('click', () => {
          const idx = parseInt(card.dataset.idx);
          const item = items[idx];
          const itemCatInfo = ENCYCLOPEDIA_CATEGORIES.find(c => c.key === item.cat) || catInfo;
          showEncyclopediaDetail(item, itemCatInfo);
        });
      });
    }

    function showEncyclopediaDetail(item, catInfo) {
      const modal = document.getElementById('encyclopediaDetailModal');
      const content = document.getElementById('encyclopediaDetailContent');
      if (!modal || !content) return;

      content.innerHTML = `
        <button onclick="closeEncyclopediaDetail()" style="position:absolute;top:12px;right:12px;width:32px;height:32px;border-radius:50%;border:none;background:rgba(0,0,0,0.06);cursor:pointer;font-size:18px;display:flex;align-items:center;justify-content:center;color:#666;">驛｢譎｢・ｽ・ｻ驛｢譎｢・ｽ・ｻ驛｢譎｢・ｽ・ｻ/button>
        <div style="text-align:center;">
          <div style="width:180px;height:180px;border-radius:16px;overflow:hidden;margin:0 auto 16px;background:#f5f0eb;box-shadow:0 4px 16px rgba(0,0,0,0.1);">
            <img src="${item.img}" alt="${item.name}" style="width:100%;height:100%;object-fit:cover;" onerror="this.style.display='none'">
          </div>
          <div style="display:inline-block;padding:4px 12px;border-radius:12px;font-size:11px;font-weight:700;background:${catInfo.color}20;color:${catInfo.color};margin-bottom:10px;">${catInfo.label}</div>
          <h3 style="font-size:20px;font-weight:800;color:#4a3728;margin:0 0 10px;">${item.name}</h3>
          <p style="font-size:14px;color:#6a5a4a;line-height:1.7;margin:0 0 12px;font-weight:600;">${item.catch || ''}</p>
          <p style="font-size:13px;color:#8a7a6a;line-height:1.6;margin:0;">${item.summary || ''}</p>
        </div>
      `;

      modal.style.display = 'flex';
      modal.style.animation = 'fadeIn 0.2s ease';

      modal.onclick = (e) => {
        if (e.target === modal) closeEncyclopediaDetail();
      };
    }

