    /* POST helper */
    async function postJSON(url, data) {
      const r = await fetch(url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });

      const j = await r.json().catch(() => ({}));

      if (!r.ok || !j.ok) {
        const msg = j?.error || "Request failed";
        throw new Error(msg);
      }
      return j;
    }

