    function setImageWithFallback(img, primarySrc, fallbackSrc) {
      if (!img) return;
      img.onerror = () => {
        img.onerror = null;
        img.src = encodeURI(fallbackSrc);
      };
      img.src = encodeURI(primarySrc || fallbackSrc);
    }

    function collectSeriesDiagnosisState(seriesId) {
      const series = getSeriesDefinition(seriesId);
      if (!series) return null;
      const primary = readStorageSnapshot(series.storageKey);
      const pending = readStorageSnapshot(series.pendingKey);
      const primaryReady = typeof series.resolveReady === "function" ? series.resolveReady(primary.data) : false;
      const pendingReady = typeof series.resolvePendingReady === "function" ? series.resolvePendingReady(pending.data) : false;
      const summary = typeof series.resolveSummary === "function"
        ? series.resolveSummary(primary.data, pending.data)
        : {};
      const selectedImage = typeof series.resolveImage === "function"
        ? series.resolveImage(summary, primary.data, pending.data)
        : series.fallbackImage;

      return {
        series,
        ready: primaryReady || pendingReady,
        source: primaryReady ? "storage" : (pendingReady ? "pending" : "none"),
        storage: primary,
        pending,
        summary,
        image: selectedImage || series.fallbackImage,
        backImage: series.backImage || "16school/key/ura.jpg"
      };
    }

    function buildStripeSheetPayloadFromStorage(extraPayload = {}) {
      const current = selectedDiagnosisState;
      const series = current?.series || {};
      const summary = current?.summary || {};

      return {
        event: "stripe_click",
        source: series.source || "acrylic_selection",
        createdAt: new Date().toISOString(),
        pageUrl: window.location.href,
        userAgent: navigator.userAgent,
        name: summary.name || "",
        age: summary.age || "",
        email: summary.email || "",
        gender: summary.gender || "",
        type: summary.type || "",
        diagnosisName: summary.diagnosisName || "",
        axes: summary.axes || {},
        answers: summary.answers || {},
        interested: summary.interested === true,
        userId: summary.userId || "",
        referrerId: summary.referrerId || "",
        shareCount: Number(summary.shareCount || 0),
        storageKey: series.storageKey || "",
        storageRaw: current?.storage?.raw || "",
        pendingStorageKey: series.pendingKey || "",
        pendingStorageRaw: current?.pending?.raw || "",
        stateSnapshot: current?.storage?.data || null,
        selectedDiagnosisSeries: series.id || "",
        selectedDiagnosisLabel: series.label || "",
        selectedDiagnosisStorageKey: series.storageKey || "",
        selectedDiagnosisRaw: current?.storage?.raw || current?.pending?.raw || "",
        selectedDiagnosisType: summary.type || "",
        selectedDiagnosisName: summary.diagnosisName || "",
        selectedDiagnosisImage: current?.image || "",
        selectedDiagnosisReady: current?.ready === true,
        ...extraPayload
      };
    }

    function sendToGoogleSheet(payload) {
      if (!GAS_WEBAPP_URL) return;
      try {
        const body = JSON.stringify(payload);
        if (navigator.sendBeacon) {
          const blob = new Blob([body], { type: "text/plain" });
          navigator.sendBeacon(GAS_WEBAPP_URL, blob);
          return;
        }
        fetch(GAS_WEBAPP_URL, {
          method: "POST",
          mode: "no-cors",
          headers: { "Content-Type": "text/plain" },
          body,
          keepalive: true
        }).catch(() => { });
      } catch (_) { }
    }

    function initStripeButtonTracking({
      buttonId,
      messageId = "",
      requireDiagnosisSelection = false,
      productType = "",
      productLabel = ""
    }) {
      const btn = document.getElementById(buttonId);
      if (!btn) return;

      btn.addEventListener("click", (e) => {
        const messageEl = messageId ? document.getElementById(messageId) : null;

        if (requireDiagnosisSelection) {
          if (!selectedDiagnosisState?.ready) {
            e.preventDefault();
            if (messageEl) {
              messageEl.style.display = "block";
            }
            return;
          }
        }

        if (messageEl) {
          messageEl.style.display = "none";
        }

        const payload = buildStripeSheetPayloadFromStorage({
          clickedProductType: productType,
          clickedProductLabel: productLabel,
          clickedButtonId: buttonId
        });
        sendToGoogleSheet(payload);
      });
    }

