    let syncPlushReservationGallery = () => { };

    function initPlushReservationGallery() {
      const root = document.getElementById("plushGallery");
      const viewport = document.getElementById("plushGalleryViewport");
      const track = document.getElementById("plushGalleryTrack");
      const dotsWrap = document.getElementById("plushGalleryDots");
      const prevBtn = document.getElementById("plushGalleryPrev");
      const nextBtn = document.getElementById("plushGalleryNext");
      const hint = document.getElementById("plushGalleryHint");

      if (!root || !viewport || !track || !dotsWrap) return;
      if (root.dataset.initialized === "true") return;

      const images = Array.from(new Set(PLUSH_RESERVATION_IMAGES));
      if (images.length === 0) return;

      const slides = [];
      const dots = [];

      images.forEach((imageItem, index) => {
        const slide = document.createElement("div");
        slide.className = "plush-gallery-slide";

        const picture = document.createElement("picture");
        if (imageItem.avif) {
          const sourceAvif = document.createElement("source");
          sourceAvif.srcset = imageItem.avif;
          sourceAvif.type = "image/avif";
          picture.appendChild(sourceAvif);
        }
        if (imageItem.webp) {
          const sourceWebp = document.createElement("source");
          sourceWebp.srcset = imageItem.webp;
          sourceWebp.type = "image/webp";
          picture.appendChild(sourceWebp);
        }

        const img = document.createElement("img");
        img.src = imageItem.png || imageItem.webp || imageItem.avif || "";
        img.alt = imageItem.alt || `鬯ｩ謳ｾ・ｽ・ｵ郢晢ｽｻ繝ｻ・ｺ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｬ鬯ｩ謳ｾ・ｽ・ｵ郢晢ｽｻ繝ｻ・ｺ鬩幢ｽ｢隴趣ｽ｢繝ｻ・ｽ繝ｻ・ｻ驛｢譎｢・ｽ・ｻ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｹ郢晢ｽｻ繝ｻ・ｧ鬮｣蛹・ｽｽ・ｵ髫ｴ謫ｾ・ｽ・ｶ鬮｣譴ｧ繝ｻ・取鱒繝ｻ繝ｻ・ｧ驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｭ鬯ｩ蟷｢・ｽ・｢髫ｴ雜｣・ｽ・｢郢晢ｽｻ繝ｻ・ｽ郢晢ｽｻ繝ｻ・ｼ鬯ｩ蟷｢・ｽ・｢髫ｴ蜿門ｾ励・・ｽ繝ｻ・ｸ髯ｷ・ｴ繝ｻ・･髫ｴ諠ｹ・ｼ螟ｲ・ｽ・ｽ繝ｻ・ｹ髫ｰ・ｨ鬲托ｽｴ・つ鬯ｩ蟷｢・ｽ・｢髫ｴ雜｣・ｽ・｢郢晢ｽｻ繝ｻ・ｽ郢晢ｽｻ繝ｻ・ｼ ${index + 1}`;
        img.loading = index === 0 ? "eager" : "lazy";
        img.decoding = "async";

        picture.appendChild(img);
        slide.appendChild(picture);
        track.appendChild(slide);
        slides.push(slide);

        const dot = document.createElement("button");
        dot.type = "button";
        dot.className = "plush-gallery-dot";
        dot.setAttribute("aria-label", `${index + 1}鬯ｮ・ｫ繝ｻ・ｴ郢晢ｽｻ繝ｻ・ｫ鬮ｯ讓奇ｽｺ蛛・ｽｽ繝ｻ繝ｻ繝ｻ・ｲ郢晢ｽｻ繝ｻ・ｼ鬯ｩ蟷｢・ｽ・｢郢晢ｽｻ繝ｻ・ｧ鬮ｯ讖ｸ・ｽ・ｳ髯樊ｻゑｽｽ・ｲ郢晢ｽｻ繝ｻ・ｽ郢晢ｽｻ繝ｻ・｡驛｢譎｢・ｽ・ｻ郢晢ｽｻ繝ｻ・ｨ鬯ｯ・ｩ驕ｨ繧托ｽｽ・ｼ陞滂ｽｲ繝ｻ・ｽ繝ｻ・ｽ郢晢ｽｻ繝ｻ・ｺ`);
        dot.addEventListener("click", () => {
          goTo(index, true);
        });
        dotsWrap.appendChild(dot);
        dots.push(dot);
      });

      let currentIndex = 0;
      let dragging = false;
      let startX = 0;
      let currentX = 0;
      let startTranslateX = 0;
      let pointerId = null;
      const maxIndex = slides.length - 1;
      const swipeThreshold = 30;

      function slideWidth() {
        return viewport.getBoundingClientRect().width || 1;
      }

      function hideHint() {
        if (!hint) return;
        if (slides.length <= 1) {
          hint.style.display = "none";
          return;
        }
        hint.classList.add("is-hidden");
      }

      function updateNav() {
        dots.forEach((dot, index) => {
          dot.classList.toggle("is-active", index === currentIndex);
        });
        if (prevBtn) prevBtn.disabled = currentIndex === 0;
        if (nextBtn) nextBtn.disabled = currentIndex === maxIndex;
        if (prevBtn) prevBtn.style.display = slides.length <= 1 ? "none" : "";
        if (nextBtn) nextBtn.style.display = slides.length <= 1 ? "none" : "";
        dotsWrap.style.display = slides.length <= 1 ? "none" : "";
      }

      function render(animated = true) {
        const width = slideWidth();
        const x = -currentIndex * width;
        track.style.transition = animated ? "transform 0.36s var(--ease-soft)" : "none";
        track.style.transform = `translateX(${x}px)`;
        updateNav();
      }

      function goTo(nextIndex, fromUser = false, animated = true) {
        currentIndex = Math.max(0, Math.min(maxIndex, nextIndex));
        render(animated);
        if (fromUser) hideHint();
      }

      function endDrag(e) {
        if (!dragging) return;
        if (pointerId !== null && e?.pointerId !== undefined && e.pointerId !== pointerId) return;

        dragging = false;
        pointerId = null;
        viewport.classList.remove("is-dragging");

        const deltaX = currentX - startX;
        if (deltaX <= -swipeThreshold && currentIndex < maxIndex) currentIndex += 1;
        if (deltaX >= swipeThreshold && currentIndex > 0) currentIndex -= 1;
        if (Math.abs(deltaX) > 6) hideHint();

        render(true);

        if (viewport.releasePointerCapture && e?.pointerId !== undefined) {
          try { viewport.releasePointerCapture(e.pointerId); } catch (_) { }
        }
      }

      viewport.addEventListener("pointerdown", (e) => {
        if (dragging || slides.length <= 1) return;

        dragging = true;
        pointerId = e.pointerId;
        startX = e.clientX;
        currentX = e.clientX;
        startTranslateX = -currentIndex * slideWidth();
        track.style.transition = "none";
        viewport.classList.add("is-dragging");

        if (viewport.setPointerCapture) {
          try { viewport.setPointerCapture(e.pointerId); } catch (_) { }
        }

        e.preventDefault();
      });

      viewport.addEventListener("pointermove", (e) => {
        if (!dragging) return;
        if (pointerId !== null && e.pointerId !== pointerId) return;

        currentX = e.clientX;
        const dx = currentX - startX;
        const width = slideWidth();
        const minTranslate = -maxIndex * width;
        let targetX = startTranslateX + dx;

        if (targetX > 0) {
          targetX *= 0.35;
        } else if (targetX < minTranslate) {
          targetX = minTranslate + (targetX - minTranslate) * 0.35;
        }

        track.style.transform = `translateX(${targetX}px)`;
        e.preventDefault();
      });

      viewport.addEventListener("pointerup", endDrag);
      viewport.addEventListener("pointercancel", endDrag);
      viewport.addEventListener("lostpointercapture", () => endDrag());

      if (prevBtn) {
        prevBtn.addEventListener("click", () => {
          goTo(currentIndex - 1, true);
        });
      }
      if (nextBtn) {
        nextBtn.addEventListener("click", () => {
          goTo(currentIndex + 1, true);
        });
      }

      viewport.addEventListener("keydown", (e) => {
        if (e.key === "ArrowRight") {
          goTo(currentIndex + 1, true);
          e.preventDefault();
          return;
        }
        if (e.key === "ArrowLeft") {
          goTo(currentIndex - 1, true);
          e.preventDefault();
        }
      });

      const sync = () => {
        if (viewport.offsetParent === null) return;
        render(false);
      };

      window.addEventListener("resize", sync, { passive: true });
      syncPlushReservationGallery = sync;

      root.dataset.initialized = "true";
      goTo(0, false, false);
    }

    function activateReservationTab(tabKey) {
      if (!tabKey) return;

      reservationTabButtons.forEach((button) => {
        const isActive = button.dataset.reservationTab === tabKey;
        button.setAttribute("aria-selected", isActive ? "true" : "false");
        button.tabIndex = isActive ? 0 : -1;
      });

      reservationTabPanels.forEach((panel) => {
        const isActive = panel.dataset.reservationPanel === tabKey;
        panel.classList.toggle("is-active", isActive);
        panel.hidden = !isActive;
      });

      if (tabKey === "plush") {
        requestAnimationFrame(() => {
          syncPlushReservationGallery();
        });
      }
    }

    reservationTabButtons.forEach((button, index) => {
      button.addEventListener("click", () => {
        activateReservationTab(button.dataset.reservationTab || "");
      });

      button.addEventListener("keydown", (e) => {
        if (!["ArrowRight", "ArrowLeft", "Home", "End"].includes(e.key)) return;
        e.preventDefault();

        let nextIndex = index;
        if (e.key === "ArrowRight") nextIndex = (index + 1) % reservationTabButtons.length;
        if (e.key === "ArrowLeft") nextIndex = (index - 1 + reservationTabButtons.length) % reservationTabButtons.length;
        if (e.key === "Home") nextIndex = 0;
        if (e.key === "End") nextIndex = reservationTabButtons.length - 1;

        const nextButton = reservationTabButtons[nextIndex];
        if (!nextButton) return;

        activateReservationTab(nextButton.dataset.reservationTab || "");
        nextButton.focus();
      });
    });

    initPlushReservationGallery();

    if (reservationTabButtons.length > 0) {
      const defaultTab = reservationTabButtons.find((button) => button.getAttribute("aria-selected") === "true")?.dataset.reservationTab
        || reservationTabButtons[0]?.dataset.reservationTab
        || "";
      activateReservationTab(defaultTab);
    }

